const express = require('express');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(express.json());

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme'
  }
});

// --- Security: Authentication & Authorization Middleware ---

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // In production, verify JWT or session token properly
  // This is a placeholder for real auth verification
  const jwt = require('jsonwebtoken');
  const JWT_SECRET = process.env.JWT_SECRET;

  if (!JWT_SECRET) {
    return res.status(500).json({ error: 'Server misconfiguration' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

function authorizeAdmin(req, res, next) {
  if (!req.user || req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Admin access required' });
  }
  next();
}

// --- Security: Index Name Allowlist & Validation ---

// Only allow querying specific indices (allowlist approach)
const ALLOWED_INDEX_PATTERNS = (process.env.ALLOWED_INDICES || 'app-*,logs-*,metrics-*').split(',').map(s => s.trim());

// Indices that must never be queried regardless of patterns
const BLOCKED_INDICES = [
  '.security',
  '.security-7',
  '.security-tokens',
  '.kibana',
  '.kibana_task_manager',
  '.tasks',
  '.apm-agent-configuration',
  '.apm-custom-link',
  '.async-search',
  '.management-beats',
  '.monitoring-*',
  '.watcher-history-*',
  '.triggered_watches',
  '.watches',
  '_all'
];

function isIndexBlocked(indexName) {
  const lowerIndex = indexName.toLowerCase();

  for (const blocked of BLOCKED_INDICES) {
    if (blocked.endsWith('*')) {
      const prefix = blocked.slice(0, -1);
      if (lowerIndex.startsWith(prefix)) return true;
    } else {
      if (lowerIndex === blocked) return true;
    }
  }

  return false;
}

function isIndexAllowed(indexName) {
  const lowerIndex = indexName.toLowerCase();

  for (const pattern of ALLOWED_INDEX_PATTERNS) {
    if (pattern.endsWith('*')) {
      const prefix = pattern.slice(0, -1).toLowerCase();
      if (lowerIndex.startsWith(prefix)) return true;
    } else {
      if (lowerIndex === pattern.toLowerCase()) return true;
    }
  }

  return false;
}

function validateIndexName(indexName) {
  // Must be a valid Elasticsearch index name
  // No wildcards that could expand to system indices, no commas (multi-index), no special patterns
  const VALID_INDEX_REGEX = /^[a-z0-9][a-z0-9._-]*$/;

  if (!indexName || typeof indexName !== 'string') {
    return { valid: false, reason: 'Index name is required and must be a string' };
  }

  if (indexName.length > 255) {
    return { valid: false, reason: 'Index name too long' };
  }

  // Disallow wildcards, commas, and special characters that could expand scope
  if (/[*,><|\/\\?#\s]/.test(indexName)) {
    return { valid: false, reason: 'Index name contains disallowed characters (wildcards, commas, etc.)' };
  }

  if (!VALID_INDEX_REGEX.test(indexName)) {
    return { valid: false, reason: 'Index name contains invalid characters' };
  }

  // Block system/internal indices
  if (indexName.startsWith('.') || indexName.startsWith('_')) {
    return { valid: false, reason: 'Access to system/internal indices is not permitted' };
  }

  if (isIndexBlocked(indexName)) {
    return { valid: false, reason: 'This index is blocked from querying' };
  }

  if (!isIndexAllowed(indexName)) {
    return { valid: false, reason: 'This index is not in the allowed list' };
  }

  return { valid: true };
}

// --- Security: Query DSL Sanitization ---

// Disallow dangerous query types and scripting
const BLOCKED_QUERY_KEYS = [
  'script',
  'script_score',
  'script_fields',
  'scripted_metric',
  'runtime_mappings',
  'stored_fields',
  '_source_excludes',
  '_source_includes',
  'indices_boost',
  'search_after',
  'pit',
  'slice'
];

const BLOCKED_AGGREGATION_TYPES = [
  'scripted_metric',
  'script'
];

function containsBlockedKeys(obj, path = '') {
  if (obj === null || obj === undefined) return null;
  if (typeof obj !== 'object') return null;

  if (Array.isArray(obj)) {
    for (let i = 0; i < obj.length; i++) {
      const result = containsBlockedKeys(obj[i], `${path}[${i}]`);
      if (result) return result;
    }
    return null;
  }

  for (const key of Object.keys(obj)) {
    const lowerKey = key.toLowerCase();

    // Check for script injection at any nesting level
    if (lowerKey === 'script' || lowerKey === 'script_id' || lowerKey === 'stored_script') {
      return `Scripting is not allowed (found at ${path}.${key})`;
    }

    if (BLOCKED_QUERY_KEYS.includes(lowerKey)) {
      return `Blocked query key: "${key}" at ${path}`;
    }

    if (BLOCKED_AGGREGATION_TYPES.includes(lowerKey)) {
      return `Blocked aggregation type: "${key}" at ${path}`;
    }

    // Recursively check nested objects
    const result = containsBlockedKeys(obj[key], `${path}.${key}`);
    if (result) return result;
  }

  return null;
}

function validateQueryBody(queryBody) {
  if (!queryBody || typeof queryBody !== 'object') {
    return { valid: false, reason: 'Query body must be a valid object' };
  }

  // Prevent prototype pollution
  if ('__proto__' in queryBody || 'constructor' in queryBody || 'prototype' in queryBody) {
    return { valid: false, reason: 'Invalid query body' };
  }

  // Check for blocked keys recursively
  const blockedKeyResult = containsBlockedKeys(queryBody);
  if (blockedKeyResult) {
    return { valid: false, reason: blockedKeyResult };
  }

  // Enforce a maximum query depth to prevent abuse
  const maxDepth = 20;
  if (getObjectDepth(queryBody) > maxDepth) {
    return { valid: false, reason: `Query nesting exceeds maximum depth of ${maxDepth}` };
  }

  // Enforce maximum result size
  if (queryBody.size !== undefined) {
    const size = parseInt(queryBody.size, 10);
    if (isNaN(size) || size < 0 || size > 1000) {
      return { valid: false, reason: 'Size must be between 0 and 1000' };
    }
  }

  if (queryBody.from !== undefined) {
    const from = parseInt(queryBody.from, 10);
    if (isNaN(from) || from < 0 || from > 10000) {
      return { valid: false, reason: 'From must be between 0 and 10000' };
    }
  }

  return { valid: true };
}

function getObjectDepth(obj, currentDepth = 0) {
  if (obj === null || obj === undefined || typeof obj !== 'object') {
    return currentDepth;
  }

  if (currentDepth > 50) return currentDepth; // Safety bail-out

  let maxChildDepth = currentDepth;

  const entries = Array.isArray(obj) ? obj : Object.values(obj);
  for (const value of entries) {
    const childDepth = getObjectDepth(value, currentDepth + 1);
    if (childDepth > maxChildDepth) {
      maxChildDepth = childDepth;
    }
  }

  return maxChildDepth;
}

// --- Rate Limiting ---

const rateLimit = require('express-rate-limit');

const searchLimiter = rateLimit({
  windowMs: 60 * 1000, // 1 minute
  max: 60, // 60 requests per minute per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many search requests, please try again later' }
});

// --- Request Size Limiting ---

app.use(express.json({ limit: '100kb' }));

// --- Logging / Audit ---

function auditLog(req, indexName, success, details = '') {
  const logEntry = {
    timestamp: new Date().toISOString(),
    user: req.user ? req.user.sub || req.user.username : 'unknown',
    ip: req.ip,
    index: indexName,
    success,
    details,
    userAgent: req.headers['user-agent']
  };
  // In production, send to a dedicated audit log / SIEM
  console.log('[AUDIT]', JSON.stringify(logEntry));
}

// --- Search Endpoint ---

app.post(
  '/api/search/:index',
  searchLimiter,
  authenticateToken,
  authorizeAdmin,
  async (req, res) => {
    const indexName = req.params.index;

    // Validate index name
    const indexValidation = validateIndexName(indexName);
    if (!indexValidation.valid) {
      auditLog(req, indexName, false, `Index validation failed: ${indexValidation.reason}`);
      return res.status(400).json({ error: indexValidation.reason });
    }

    // Validate query body
    const queryBody = req.body.query;
    if (!queryBody) {
      auditLog(req, indexName, false, 'Missing query body');
      return res.status(400).json({ error: 'Request body must contain a "query" object' });
    }

    const queryValidation = validateQueryBody(queryBody);
    if (!queryValidation.valid) {
      auditLog(req, indexName, false, `Query validation failed: ${queryValidation.reason}`);
      return res.status(400).json({ error: queryValidation.reason });
    }

    // Enforce safe defaults
    const safeQuery = {
      ...queryBody,
      size: Math.min(parseInt(queryBody.size, 10) || 10, 1000),
      from: Math.min(parseInt(queryBody.from, 10) || 0, 10000)
    };

    // Remove any top-level keys we don't want forwarded
    delete safeQuery.scroll;
    delete safeQuery.search_type;
    delete safeQuery.request_cache;
    delete safeQuery.allow_partial_search_results;

    try {
      // Verify the index actually exists before searching
      const indexExists = await esClient.indices.exists({ index: indexName });
      if (!indexExists) {
        auditLog(req, indexName, false, 'Index does not exist');
        return res.status(404).json({ error: 'Index not found' });
      }

      const result = await esClient.search({
        index: indexName,
        body: safeQuery,
        // Enforce timeout at the Elasticsearch level
        timeout: '30s',
        // Do not allow partial results
        allow_partial_search_results: false
      });

      auditLog(req, indexName, true, `Returned ${result.hits.hits.length} hits`);

      return res.json({
        took: result.took,
        timed_out: result.timed_out,
        total: result.hits.total,
        hits: result.hits.hits,
        aggregations: result.aggregations || undefined
      });
    } catch (err) {
      auditLog(req, indexName, false, `Search error: ${err.message}`);

      // Don't leak internal Elasticsearch error details to the client
      if (err.meta && err.meta.statusCode) {
        const statusCode = err.meta.statusCode;
        if (statusCode === 400) {
          return res.status(400).json({ error: 'Invalid query syntax' });
        }
        if (statusCode === 404) {
          return res.status(404).json({ error: 'Index not found' });
        }
        if (statusCode === 403) {
          return res.status(403).json({ error: 'Access denied to this index' });
        }
      }

      console.error('[ERROR] Elasticsearch search failed:', err.message);
      return res.status(500).json({ error: 'Search failed. Please try again later.' });
    }
  }
);

